<template>
  <!-- HEADER AREA START -->
  <header>
    <!-- MAIN MENUBAR AREA START -->
    <div class="main-menubar">
      <nav class="navbar navbar-expand-lg menu fixed" :class="{topHeaderBG : scrolling}">
        <button class="navbar-toggler" type="button" data-toggle="collapse" data-target="#navbarTogglerDemo01"
                aria-controls="navbarTogglerDemo01" aria-expanded="false" aria-label="Toggle navigation">
          <i class="navbar-icon fa fa-bars"></i>
        </button>
        <router-link class="navbar-brand logo-right" to="/">
          <img :src="showImage(generalSettings.logo_black)" width="90px" height="20px" alt="Loyer Logo">
        </router-link>
        <div class="collapse navbar-collapse" id="navbarTogglerDemo01">


          <div class="search-box">
            <form>
              <input type="search" placeholder="Search" aria-label="Search">
              <button type="submit"><i class="fa fa-search" aria-hidden="true"></i></button>
            </form>
          </div>


          <ul class="navbar-nav right-nav mt-2 mt-lg-0">
            <li class="nav-item">
              <a class="nav-link" href="#">
                <i class="fa fa-shopping-cart" aria-hidden="true"></i>
                <br>
                <!--                                <span>Cart</span>-->
              </a>
            </li>
            <li class="nav-item">
              <a class="nav-link" href="#">
                <i class="fa fa-heart-o"></i>
                <br>
                <!--                                <span>Wishlist</span>-->
              </a>
            </li>
            <li class="nav-item">
              <a class="nav-link" href="#">
                <i class="fa fa-bars" aria-hidden="true"></i>
                <br>
                <!--                                <span>Menu</span>-->
              </a>
            </li>
            <li class="nav-item">
              <a-dropdown overlayClassName="header-droupdown">
                <a class="nav-link ant-dropdown-link" @click="e => e.preventDefault()">
                  <i class="fa fa-user-circle-o"></i>
                  <br>
                </a>
                <a-menu slot="overlay">
                  <a-menu-item class="text-center" style="width: 250px">
                    <span style="font-size: 10px;white-space: normal">
                      <span class="font-weight-bold">Welcome to {{$store.getters.generalSettings.app_name}} Shopping</span><br>
                      Sign Up or Login for a personalised experience and faster checkout!
                    </span>
                    <a-button type="danger" class="mt-2" @click="$router.push('/login')">
                      Login / Sign-up
                    </a-button>
                  </a-menu-item>
                </a-menu>
              </a-dropdown>
            </li>


          </ul>
        </div>
      </nav>

    </div>
    <!-- MAIN MENUBAR AREA END-->

    <!--        ********************* menu part start *************************-->
    <section style="margin-top: 100px" id="categorie">
      <div class="categorie-menu">
        <ul class="mb-0">
          <li v-for="categories in categoryList.slice(0,13)" :key="categories.id">
            <a href="#">{{ categories.name }}</a>
          </li>
        </ul>
      </div>
    </section>
    <!--        ********************* menu part end ***************************-->
  </header>
  <!-- HEADER AREA END -->
</template>

<script>
import {mapGetters} from 'vuex';

export default {
  name: "Header",
  data() {
    return {
      scrolling: true,
    }
  },
  created() {
    window.addEventListener('scroll', this.handleScroll);
  },
  methods: {
    handleScroll() {
      if (window.scrollY > 20) {
        this.scrolling = false
      } else {
        this.scrolling = true
      }
    }
  },
  computed: {
    ...mapGetters(["generalSettings", "categoryList", "isBangla"])
  },
}
</script>

<style scoped>
.topHeaderBG {
  background: #f1f1f1;
}
</style>
